vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret0 = GetPixel(vUv);
rsl = rs_lav (vUv-0.5,ret0.b*0.5+.5);
mod = texture(sampler_noise_mq, rsl*0.00007+modran.yx);
mod2 = texture(sampler_noise_mq, rsl*0.00005+modran);
fog = 3.2 + 0.5*mod2.x;
ret = ret0;;;
ret = mix(GetBlur1(vUv),ret0.r,ret0.g*3) ;
ret = ret.r;

ret = mix(ret, ret0,sat(ret0.g*ret0.g*gmod));
lake = max(sat (6*(ret0.b -0.9)) * pow(texture3D(sampler_noisevol_lq,0.05*rsl*vec3 (1,1,0.2)),4)*4*sat(50/abs(rsl.z)),
            sat (4*ret0.b-fog))*normalize(mod);


//ret = max(lake,ret);
ret += lake;
//ret = ret0.g;

  fragColor = ret;
}
